const body = $('Webhook').first().json.body;

const nb_tools = parseInt(body.nb_tools) || 0;
const nb_bash = parseInt(body.nb_bash) || 0;
const nb_errors = parseInt(body.nb_errors) || 0;
const nb_compacts = parseInt(body.nb_compacts) || 0;
const topics = Array.isArray(body.topics) ? body.topics : (body.topics ? [body.topics] : []);
const duration_min = parseFloat(body.duration_min) || 0;
const session_file = body.session_file || null;
const project = body.project || 'VPAI';

const needs_alert = (nb_errors > 10 || nb_compacts > 3);

return [{ json: { nb_tools, nb_bash, nb_errors, nb_compacts, topics, duration_min, session_file, project, needs_alert } }];

const { spawnSync } = require('child_process');
const data = $input.first().json;

const WAZA_HOST = $env.WORKSTATION_PI_IP || '100.64.0.1';
const WAZA_USER = $env.WORKSTATION_PI_USER || 'mobuone';
const SSH_KEY = $env.WORKSTATION_SSH_KEY_PATH || '/home/node/.ssh/id_ed25519';
const SPOOL_DIR = '/opt/workstation/data/ai-memory-worker/spool';

const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const filename = 'session-complete-' + timestamp + '.json';

const payload = JSON.stringify({
  type: 'session_summary',
  project: data.project,
  nb_tools: data.nb_tools,
  nb_bash: data.nb_bash,
  nb_errors: data.nb_errors,
  nb_compacts: data.nb_compacts,
  topics: data.topics,
  duration_min: data.duration_min,
  session_file: data.session_file,
  timestamp: new Date().toISOString()
}, null, 2);

const result = spawnSync('ssh', [
  '-i', SSH_KEY,
  '-o', 'StrictHostKeyChecking=no',
  '-o', 'BatchMode=yes',
  WAZA_USER + '@' + WAZA_HOST,
  'mkdir -p ' + SPOOL_DIR + ' && cat > ' + SPOOL_DIR + '/' + filename
], {
  input: payload,
  timeout: 15000,
  encoding: 'utf8'
});

const memoryPushed = result.status === 0;
return [{ json: { ...data, memoryPushed, spoolFile: filename } }];

const data = $input.first().json;
const NOCODB_TOKEN = $env.NOCODB_API_TOKEN;
const TABLE_ID = 'mu29gisnsp222km';

const reasons = [];
if (data.nb_errors > 10) reasons.push(data.nb_errors + ' errors');
if (data.nb_compacts > 3) reasons.push(data.nb_compacts + ' auto-compacts');

const title = 'Session Alert: ' + data.project + ' â€” ' + reasons.join(', ');
const description = 'Topics: ' + (data.topics || []).join(', ') + '\n' +
  'Duration: ' + data.duration_min + ' min\n' +
  'Tools: ' + data.nb_tools + ' | Bash: ' + data.nb_bash + '\n' +
  (data.session_file ? 'File: ' + data.session_file : '');

const response = await fetch('http://javisi_nocodb:8080/api/v2/tables/' + TABLE_ID + '/records', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'xc-token': NOCODB_TOKEN
  },
  body: JSON.stringify({
    Title: title,
    Description: description,
    Status: 'open',
    Project: data.project
  })
});

const result = await response.json();
return [{ json: { ...data, incidentId: result.Id || result.id } }];

const data = $input.first().json;
const token = $env.TELEGRAM_MONITORING_BOT_TOKEN;
const chatId = $env.TELEGRAM_MONITORING_CHAT_ID;

const parts = [];
if (data.nb_errors > 10) parts.push(data.nb_errors + ' erreurs');
if (data.nb_compacts > 3) parts.push(data.nb_compacts + ' auto-compacts');

const text = '<b>Session Alert â€” ' + data.project + '</b>\n' +
  'Problemes: ' + parts.join(', ') + '\n' +
  'Topics: ' + (data.topics || []).join(', ') + '\n' +
  'Duree: ' + data.duration_min + ' min | Tools: ' + data.nb_tools + ' | Bash: ' + data.nb_bash + '\n' +
  (data.incidentId ? 'Incident NocoDB #' + data.incidentId : '');

await fetch('https://api.telegram.org/bot' + token + '/sendMessage', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML' })
});

return [{ json: data }];
